class Solution(object):
    def distributeCandies(self, n, limit):
        # Enumerate first child's candies i in [0, min(limit, n)]
        # For second child j: max(0, n-i-limit) <= j <= min(limit, n-i)
        ans = 0
        for i in range(min(limit, n) + 1):
            lo = max(0, n - i - limit)
            hi = min(limit, n - i)
            if hi >= lo:
                ans += hi - lo + 1
        return ans
